export async function createExternalChannelMediaTransferApprovalSignature(
  candidate: ExternalChannelMediaTransferCandidate,
): Promise<string> {
  const normalized = normalizeCandidate(candidate);
  if (!normalized.accepted || !normalized.candidate) {
    return `channel-media-transfer:${normalizeChannelId(candidate.channelId)}:invalid`;
  }
  const digest = await sha256Hex(canonicalApprovalPayload(normalized.candidate));
  return `channel-media-transfer:${normalized.candidate.channelId}:${digest}`;
}

export async function planExternalChannelMediaTransfers(
  candidates: ExternalChannelMediaTransferCandidate[],
  options: ExternalChannelMediaTransferPlanningOptions = {},
): Promise<ExternalChannelMediaTransferPlan[]> {
  const plans: ExternalChannelMediaTransferPlan[] = [];
  const approvals = options.approvals ?? [];
  for (const candidate of candidates) {
    const normalized = normalizeCandidate(candidate);
    if (!normalized.accepted || !normalized.candidate) {
      plans.push({
        channelId: normalizeChannelId(candidate.channelId),
        displayName: displayNameForChannel(candidate.channelId),
        accepted: false,
        approvalRequired: true,
        reason: normalized.reason,
        redactedConfig: await redactCandidateConfig(candidate),
      });
      continue;
    }

    const requiredSignature = await createExternalChannelMediaTransferApprovalSignature(normalized.candidate);
    const approval = approvals.find((entry) => entry.signature === requiredSignature);
    const approvalAccepted =
      typeof approval?.signature === "string" &&
      approval.signature === requiredSignature &&
      typeof approval.approvedBy === "string" &&
      Boolean(approval.approvedBy.trim());

    plans.push({
      channelId: normalized.candidate.channelId,
      displayName: displayNameForChannel(normalized.candidate.channelId),
      accepted: approvalAccepted,
      approvalRequired: true,
      requiredSignature,
      ...(approvalAccepted ? {} : { reason: "Exact operator approval signature is required before external media transfer handoff." }),
      redactedConfig: await redactCandidateConfig(normalized.candidate),
    });
  }
  return plans;
}

export async function preflightExternalChannelMediaTransferManualRetryWorkItemReplay(
  request: ExternalChannelMediaTransferManualRetryWorkItemReplayPreflightRequest,
): Promise<ExternalChannelMediaTransferManualRetryWorkItemReplayPreflightResult> {
  const normalized = normalizeCandidate(request.candidate);
  if (!normalized.accepted || !normalized.candidate) {
    return manualRetryWorkItemReplayPreflightRejected("invalid_candidate");
  }

  const requiredSignature = await createExternalChannelMediaTransferApprovalSignature(normalized.candidate);
  const approvalFresh = isApprovalFreshForManualRetryReplay(
    request.approval?.approvedAt,
    request.freshApprovalRequiredAfter,
  );
  const approvalAccepted =
    typeof request.approval?.signature === "string" &&
    request.approval.signature === requiredSignature &&
    typeof request.approval.approvedBy === "string" &&
    Boolean(request.approval.approvedBy.trim()) &&
    approvalFresh;
  if (!approvalAccepted) {
    return manualRetryWorkItemReplayPreflightRejected("fresh_approval_required");
  }

  const workItem = sanitizeManualRetryReplayWorkItem(request.workItem);
  if (!workItem) {
    return manualRetryWorkItemReplayPreflightRejected("valid_work_item_required");
  }
  if (request.expectedRetryStage && request.expectedRetryStage !== workItem.retryStage) {
    return manualRetryWorkItemReplayPreflightRejected("retry_stage_mismatch", { retryStage: workItem.retryStage });
  }

  const action = await buildHostAction(normalized.candidate);
  const sourceData = manualRetrySourceRefFingerprintData(action);
  const targetData = await manualRetryTargetCorrelationHandoffData(action);
  const sourceRefFingerprints = sanitizeManualRetryWorkItemSourceRefs(sourceData.manualRetrySourceRefFingerprints);
  const targetKind = isTargetKind(targetData.manualRetryTargetKind) ? targetData.manualRetryTargetKind : action.targetKind;
  const targetCorrelationFingerprint = typeof targetData.manualRetryTargetCorrelationFingerprint === "string"
    ? targetData.manualRetryTargetCorrelationFingerprint
    : "";
  const expectedWorkItemCorrelationId = await manualRetryWorkItemCorrelationId({
    retryStage: workItem.retryStage,
    transferKey: action.transferKey,
    sourceRefFingerprints,
    targetKind,
    targetCorrelationFingerprint,
  });

  const transferKeyMatched = workItem.transferKey === action.transferKey;
  const targetCorrelationMatched =
    workItem.targetKind === targetKind &&
    workItem.targetCorrelationFingerprint === targetCorrelationFingerprint;
  const sourceRefFingerprintsMatched = manualRetryWorkItemSourceRefsEqual(
    workItem.sourceRefFingerprints,
    sourceRefFingerprints,
  );
  const workItemCorrelationMatched = workItem.workItemCorrelationId === expectedWorkItemCorrelationId;
  const accepted =
    transferKeyMatched &&
    targetCorrelationMatched &&
    sourceRefFingerprintsMatched &&
    workItemCorrelationMatched;

  return {
    ...manualRetryWorkItemReplayPreflightBase(workItem.retryStage),
    accepted,
    ...(accepted ? {} : { reasonCode: "work_item_current_truth_mismatch" }),
    retryStage: workItem.retryStage,
    workItemCorrelationId: workItem.workItemCorrelationId,
    expectedWorkItemCorrelationId,
    workItemCorrelationMatched,
    transferKeyMatched,
    targetCorrelationMatched,
    sourceRefFingerprintsMatched,
  };
}

export async function createExternalChannelMediaTransferManualRetryReplayHostAction(
  request: ExternalChannelMediaTransferManualRetryReplayHostActionRequest,
): Promise<ExternalChannelMediaTransferManualRetryReplayHostActionResult> {
  const preflight = await preflightExternalChannelMediaTransferManualRetryWorkItemReplay(request);
  if (!preflight.accepted) {
    return { accepted: false, reasonCode: preflight.reasonCode, preflight };
  }

  const normalized = normalizeCandidate(request.candidate);
  const workItem = sanitizeManualRetryReplayWorkItem(request.workItem);
  if (!normalized.accepted || !normalized.candidate || !workItem || !preflight.expectedWorkItemCorrelationId) {
    return {
      accepted: false,
      reasonCode: "replay_host_action_truth_unavailable",
      preflight: {
        ...preflight,
        accepted: false,
        reasonCode: "replay_host_action_truth_unavailable",
      },
    };
  }

  const action = await buildHostAction(normalized.candidate);
  const sourceData = manualRetrySourceRefFingerprintData(action);
  const targetData = await manualRetryTargetCorrelationHandoffData(action);
  const sourceRefFingerprints = sanitizeManualRetryWorkItemSourceRefs(sourceData.manualRetrySourceRefFingerprints);
  const targetKind = isTargetKind(targetData.manualRetryTargetKind) ? targetData.manualRetryTargetKind : action.targetKind;
  const targetCorrelationFingerprint = typeof targetData.manualRetryTargetCorrelationFingerprint === "string" &&
    /^manual-retry-target:[a-f0-9]{64}$/.test(targetData.manualRetryTargetCorrelationFingerprint)
    ? targetData.manualRetryTargetCorrelationFingerprint
    : undefined;
  if (!targetCorrelationFingerprint) {
    return {
      accepted: false,
      reasonCode: "replay_host_action_truth_unavailable",
      preflight: {
        ...preflight,
        accepted: false,
        reasonCode: "replay_host_action_truth_unavailable",
      },
    };
  }

  return {
    accepted: true,
    preflight,
    hostAction: {
      action: "external_media_transfer_manual_retry_reinvoke",
      replayMode: "manual_operator_reinvoke_preflight",
      replayActionVersion: 1,
      channelId: action.channelId,
      targetKind,
      retryStage: workItem.retryStage,
      workItemCorrelationId: workItem.workItemCorrelationId,
      expectedWorkItemCorrelationId: preflight.expectedWorkItemCorrelationId,
      transferKey: action.transferKey,
      sourceRefFingerprints,
      sourceRefsTruncated: sourceData.manualRetrySourceRefsTruncated === true,
      targetCorrelationFingerprint,
      requiresFreshApprovalSignature: true,
      requiresSourceRefRevalidation: true,
      requiresFreshSourceResolution: true,
      mustNotReuseResolvedFiles: true,
      requiresVendorStateCheck: workItem.retryStage === "vendor_send",
      replayAcceptedByHostClaim: false,
      hostExecutionRequired: true,
      colonyExecutedHostHandler: false,
      workItemPersisted: false,
      retryLedgerCreated: false,
      durableRetryAuditRecordCreated: false,
      backgroundRetryCreated: false,
      retryWorkerCreated: false,
      retryScheduleCreated: false,
      automaticVendorRetryAllowed: false,
      credentialPersistenceCreated: false,
      defaultLiveDeliveryEnabled: false,
      publicHostingEnabled: false,
      replayActionTruth: "credential_free_host_owned_manual_reinvoke_action_no_execution",
    },
  };
}

