    return manualRetryControlWorkerInvocationExecutionReceiptRejected(
      retryControlWorkerInvocationHandoffPreflight.reasonCode ??
        "external_media_transfer_manual_retry_control_worker_invocation_handoff_preflight_required",
      retryControlWorkerInvocationHandoffPreflight,
    );
