function syntheticRetryLedgerEntryWorkerExecutionAction(
  executionPlan:
    ExternalChannelMediaTransferManualRetryControlWorkerInvocationExecutionReceiptWorkItemClosureRetryLedgerEntryWorkerExecutionPlan,
): ExternalChannelMediaTransferHostAction {
  const files = executionPlan.sourceRefFingerprints.map((sourceRef) => ({
    sourceRef: `host-media:${sourceRef.sourceRefFingerprint.slice(0, 64)}`,
    sourceRefFingerprint: sourceRef.sourceRefFingerprint,
  }));
  return {
    channelId: executionPlan.channelId,
    displayName: displayNameForChannel(executionPlan.channelId),
    transferKey: executionPlan.transferKey,
    targetKind: executionPlan.targetKind,
    targetId: "redacted-host-owned-target",
    files,
    fileCount: executionPlan.sourceRefFingerprints.length,
    filesTruncated: executionPlan.sourceRefsTruncated,
    liveDeliveryEnabled: false,
    defaultPublicHostingEnabled: false,
    credentialPersistenceCreated: false,
  };
}

function retryLedgerEntryWorkerExecutionHostResult(
  executionPlan:
    ExternalChannelMediaTransferManualRetryControlWorkerInvocationExecutionReceiptWorkItemClosureRetryLedgerEntryWorkerExecutionPlan,
  handlerResult: ExternalChannelMediaTransferHandlerResult,
): ExternalChannelMediaTransferHostResult {
  const deliveredCount = Number.isSafeInteger(handlerResult.deliveredCount)
    ? Math.max(0, Math.min(executionPlan.sourceRefFingerprints.length, Number(handlerResult.deliveredCount)))
    : executionPlan.sourceRefFingerprints.length;
  const transferKeyEchoMatched = handlerResult.transferKey === executionPlan.transferKey;
  return {
    handled: true,
    command: "channels",
    output: "External media retry-ledger worker execution was performed by the host-owned foreground handler.",
    isError: handlerResult.accepted !== true || !transferKeyEchoMatched,
    data: {
      action: handlerResult.accepted === true && transferKeyEchoMatched
        ? "channels_external_media_retry_ledger_entry_worker_execution_executed"
        : "channels_external_media_retry_ledger_entry_worker_execution_rejected",
      channelId: executionPlan.channelId,
      targetKind: executionPlan.targetKind,
      transferKey: executionPlan.transferKey,
      transferKeyEchoMatched,
      fileCount: executionPlan.sourceRefFingerprints.length,
      filesTruncated: executionPlan.sourceRefsTruncated,
      deliveredCount,
      receiptMetadataIncluded: typeof handlerResult.receipt === "object" && handlerResult.receipt !== null,
      liveDeliveryEnabled: false,
      defaultPublicHostingEnabled: false,
      credentialPersistenceCreated: false,
      retryable: false,
    },
  };
}

