    workItemClosureAuditRecordPersistencePreflightAccepted: true,
    workItemClosureAuditRecordPersistenceStillTrusted: true,
    closeoutRecordPersistencePreflightAccepted: true,
    recordPlanPreflightAccepted: true,
    durableCloseoutRecordReady: true,
    manualRetryWorkItemClosedByColony: true,
    workItemClosurePersisted: true,
    closurePersistencePreflightAccepted: true,
    closeoutRecordPersisted: true,
    auditRecordPlanPreflightAccepted: true,
    retryControlWorkerInvocationExecutionReceiptPersisted: false,
    retryLedgerEntryAlreadyPersisted: true,
    durableRetryAuditRecordAlreadyPersisted: true,
