function credentialRefsEqual(left: string[], right: string[]): boolean {
  return stableJson([...left].sort()) === stableJson([...right].sort());
}

function sanitizeManualRetrySourceRevalidationResultSources(
  value: unknown,
): ExternalChannelMediaTransferManualRetryReplaySourceRevalidationResultSource[] | undefined {
  if (!Array.isArray(value) || value.length < 1 || value.length > MAX_HOST_FILE_REFS) return undefined;
  const out: ExternalChannelMediaTransferManualRetryReplaySourceRevalidationResultSource[] = [];
  for (const item of value) {
    if (!isRecord(item)) return undefined;
    if (!recordKeysAllowed(item, MANUAL_RETRY_SOURCE_REVALIDATION_RESULT_SOURCE_KEYS)) return undefined;
    if (!Number.isSafeInteger(item.fileIndex)) return undefined;
    const fileIndex = Number(item.fileIndex);
    if (fileIndex < 0 || fileIndex >= MAX_HOST_FILE_REFS) return undefined;
    const sourceRefFingerprint = typeof item.sourceRefFingerprint === "string"
      ? item.sourceRefFingerprint.trim().toLowerCase()
      : "";
    if (!SOURCE_REF_FINGERPRINT_PATTERN.test(sourceRefFingerprint)) return undefined;
    if (item.freshSourceResolutionConfirmed !== true) return undefined;
    if (item.staleResolvedFileReused !== false) return undefined;
    if (item.hostOwned !== true) return undefined;
    if (item.colonyResolvedSource !== false) return undefined;
    if (item.rawSourceRefIncluded !== false) return undefined;
    if (item.resolvedFileHandleIncluded !== false) return undefined;
    if (item.fileBytesIncluded !== false) return undefined;
    if (item.privateUrlIncluded !== false) return undefined;
    if (item.credentialIncluded !== false) return undefined;
    if (item.persisted !== false) return undefined;

    out.push({
      fileIndex,
      sourceRefFingerprint,
      freshSourceResolutionConfirmed: true,
      staleResolvedFileReused: false,
      hostOwned: true,
      colonyResolvedSource: false,
      rawSourceRefIncluded: false,
      resolvedFileHandleIncluded: false,
      fileBytesIncluded: false,
      privateUrlIncluded: false,
      credentialIncluded: false,
      persisted: false,
    });
  }
  return out;
}

function manualRetrySourceRevalidationResultSourcesEqual(
  left: ExternalChannelMediaTransferManualRetryReplaySourceRevalidationResultSource[],
  right: ExternalChannelMediaTransferManualRetryReplaySourceRevalidationResultSource[],
): boolean {
  const stableSources = (sources: ExternalChannelMediaTransferManualRetryReplaySourceRevalidationResultSource[]) =>
    sources.map((source) => ({
      fileIndex: source.fileIndex,
      sourceRefFingerprint: source.sourceRefFingerprint,
      freshSourceResolutionConfirmed: source.freshSourceResolutionConfirmed,
      staleResolvedFileReused: source.staleResolvedFileReused,
    }));
  return stableJson(stableSources(left)) === stableJson(stableSources(right));
}

function isManualRetrySourceRevalidationChecklistActionCode(
  value: unknown,
): value is ExternalChannelMediaTransferManualRetryReplaySourceRevalidationChecklistActionCode {
  return value === "verify_fresh_approval_signature" ||
    value === "verify_vendor_state_before_reinvoke" ||
    value === "resolve_source_from_approved_ref" ||
    value === "verify_no_stale_resolved_file_reuse" ||
    value === "run_host_owned_manual_reinvoke";
}

function sanitizeManualRetryWorkItemSourceRefs(
  value: unknown,
): ExternalChannelMediaTransferManualRetryWorkItemSourceRef[] {
  if (!Array.isArray(value)) return [];
  const out: ExternalChannelMediaTransferManualRetryWorkItemSourceRef[] = [];
  for (const item of value) {
    if (out.length >= MAX_HOST_FILE_REFS) break;
    if (!isRecord(item)) continue;
    if (!Number.isSafeInteger(item.fileIndex)) continue;
    const fileIndex = Math.max(0, Math.min(MAX_HOST_FILE_REFS - 1, Number(item.fileIndex)));
    const sourceRefFingerprint = typeof item.sourceRefFingerprint === "string"
      ? item.sourceRefFingerprint.trim().toLowerCase()
      : "";
    if (!SOURCE_REF_FINGERPRINT_PATTERN.test(sourceRefFingerprint)) continue;
    out.push({
      fileIndex,
      sourceRefFingerprint,
      sourceRefRevalidationRequired: true,
    });
  }
  return out;
}

function sanitizeManualRetryReplayWorkItem(
  value: unknown,
): ExternalChannelMediaTransferManualRetryWorkItem | undefined {
  if (!isRecord(value)) return undefined;
  if (!recordKeysAllowed(value, MANUAL_RETRY_WORK_ITEM_KEYS)) return undefined;
  const retryStage = isManualRetryStage(value.retryStage) ? value.retryStage : undefined;
  if (!retryStage) return undefined;
  if (value.kind !== "external_media_transfer_manual_retry_work_item") return undefined;
  if (value.workItemVersion !== 1) return undefined;
  if (value.retryMode !== "manual_operator_reinvoke") return undefined;
  const workItemCorrelationId = typeof value.workItemCorrelationId === "string"
    ? value.workItemCorrelationId.trim().toLowerCase()
    : "";
  if (!/^manual-retry-work-item:[a-f0-9]{64}$/.test(workItemCorrelationId)) return undefined;
  if (value.workItemCorrelationTruth !== "derived_from_transfer_stage_target_and_source_fingerprints_no_retry_ledger") return undefined;
  const transferKey = typeof value.transferKey === "string" ? value.transferKey.trim().toLowerCase() : "";
  if (!/^media-transfer:[a-f0-9]{64}$/.test(transferKey)) return undefined;
  if (!isTargetKind(value.targetKind)) return undefined;
  const targetCorrelationFingerprint = typeof value.targetCorrelationFingerprint === "string"
    ? value.targetCorrelationFingerprint.trim().toLowerCase()
    : "";
  if (!/^manual-retry-target:[a-f0-9]{64}$/.test(targetCorrelationFingerprint)) return undefined;
  const sourceRefFingerprints = sanitizeManualRetryReplayWorkItemSourceRefs(value.sourceRefFingerprints);
  if (!sourceRefFingerprints) return undefined;

  if (value.requiresFreshApprovalSignature !== true) return undefined;
  if (value.requiresSourceRefRevalidation !== true) return undefined;
  if (value.requiresFreshSourceResolution !== true) return undefined;
  if (value.mustNotReuseResolvedFiles !== true) return undefined;
  if (value.requiresVendorStateCheck !== (retryStage === "vendor_send")) return undefined;
  if (value.automaticVendorRetryAllowed !== false) return undefined;
  if (value.workItemPersisted !== false) return undefined;
  if (value.retryLedgerCreated !== false) return undefined;
  if (value.durableRetryAuditRecordCreated !== false) return undefined;
  if (value.backgroundRetryCreated !== false) return undefined;
  if (value.retryWorkerCreated !== false) return undefined;
  if (value.retryScheduleCreated !== false) return undefined;
  if (value.credentialPersistenceCreated !== false) return undefined;
  if (value.defaultLiveDeliveryEnabled !== false) return undefined;
  if (value.publicHostingEnabled !== false) return undefined;
  if (value.workItemTruth !== "operator_reinvoke_only_not_executable_worker_or_schedule") return undefined;

  const recommendedWaitSeconds = boundedRetryAfterSeconds(value.recommendedWaitSeconds);
  return {
    kind: "external_media_transfer_manual_retry_work_item",
    workItemVersion: 1,
    retryMode: "manual_operator_reinvoke",
    retryStage,
    workItemCorrelationId,
    workItemCorrelationTruth: "derived_from_transfer_stage_target_and_source_fingerprints_no_retry_ledger",
    transferKey,
    sourceRefFingerprints,
    sourceRefsTruncated: value.sourceRefsTruncated === true,
    targetKind: value.targetKind,
    targetCorrelationFingerprint,
    ...(recommendedWaitSeconds !== undefined ? { recommendedWaitSeconds } : {}),
    requiresFreshApprovalSignature: true,
    requiresSourceRefRevalidation: true,
    requiresFreshSourceResolution: true,
    mustNotReuseResolvedFiles: true,
    requiresVendorStateCheck: retryStage === "vendor_send",
    automaticVendorRetryAllowed: false,
    workItemPersisted: false,
    retryLedgerCreated: false,
    durableRetryAuditRecordCreated: false,
    backgroundRetryCreated: false,
    retryWorkerCreated: false,
    retryScheduleCreated: false,
    credentialPersistenceCreated: false,
    defaultLiveDeliveryEnabled: false,
    publicHostingEnabled: false,
    workItemTruth: "operator_reinvoke_only_not_executable_worker_or_schedule",
  };
}

