function freezeExternalMediaTransferObjectGraph(value: unknown, seen = new WeakSet<object>()): void {
  if (value === null || typeof value !== "object") return;
  if (seen.has(value)) return;
  seen.add(value);
  for (const nested of Object.values(value as Record<string, unknown>)) {
    freezeExternalMediaTransferObjectGraph(nested, seen);
  }
  Object.freeze(value);
}

