function toManualRetryCloseoutRecordIso(value: unknown): string {
  const date = value instanceof Date ? value : typeof value === "string" ? new Date(value) : new Date(NaN);
  if (!Number.isFinite(date.getTime())) throw new Error("invalid closeout record timestamp");
  return date.toISOString();
}

function safeManualRetryCloseoutRecordActor(value: unknown): string | undefined {
  if (value === undefined) return undefined;
  if (typeof value !== "string") return undefined;
  const clean = value.replace(/[\0\r\n]/g, "").trim();
  if (clean.length === 0 || clean.length > 120) return undefined;
  if (SECRET_VALUE_TEST_PATTERN.test(clean) || PRIVATE_URL_TEST_PATTERN.test(clean) || containsUnsafeIdentifierText(clean)) {
    return undefined;
  }
  return /^[A-Za-z0-9_.:@ -]+$/.test(clean) ? clean : undefined;
}

