function sanitizeForegroundRetryData(
  value: unknown,
  actionFileCount: number,
  actionFiles: ExternalChannelMediaFileRef[] = [],
): Record<string, unknown> {
  if (!isRecord(value)) return {};
  if (value.automaticRetryMode !== "bounded_foreground_retry") return {};
  if (value.retryStage !== "source_resolution") return {};
  if (value.retryStatus !== "recovered" && value.retryStatus !== "exhausted") return {};

  const maxAttemptCount = clampInteger(value.maxAttemptCount, 1, MAX_FOREGROUND_RETRY_ATTEMPTS);
  const fileCount = clampInteger(actionFileCount, 0, MAX_HOST_FILE_REFS);
  const maxRetryAttempts = Math.max(0, fileCount * (maxAttemptCount - 1));
  const sourceFileOutcomes = sanitizeSourceFileRetryOutcomes(
    value.sourceFileOutcomes,
    actionFiles,
    maxAttemptCount,
  );
  return {
    foregroundRetry: {
      automaticRetryMode: "bounded_foreground_retry",
      retryStage: "source_resolution",
      retryStatus: value.retryStatus,
      retryAttemptCount: clampInteger(value.retryAttemptCount, 0, maxRetryAttempts),
      maxAttemptCount,
      fileCount,
      ...(sourceFileOutcomes.length > 0 ? { sourceFileOutcomes } : {}),
      retryWorkerCreated: false,
      retryScheduleCreated: false,
      metadataTruth: "host_reported_retry_metadata",
    },
  };
}

function sanitizeManualRetrySafetyData(value: unknown): Record<string, unknown> {
  if (!isRecord(value)) return {};
  const retryStage = typeof value.retryStage === "string"
    ? value.retryStage.trim().toLowerCase()
    : "";
  if (!SAFE_MANUAL_RETRY_SAFETY_STAGES.has(retryStage)) return {};

  if (retryStage === "vendor_send") {
    return {
      manualRetryStage: "vendor_send",
      manualRetryReasonCode: "vendor_send_retryable_failure",
      manualRetryVerificationScope: "vendor_state_then_source_ref_revalidation",
      manualRetryNextOperatorAction: "Verify vendor-side send state before operator reinvoke, then revalidate source refs and re-run the approved external media transfer only if the vendor has not already accepted the send.",
      manualRetryRequiresVendorStateCheck: true,
      sourceResolveCompletedBeforeRetry: true,
      vendorSendAttemptedBeforeRetry: true,
      operatorMustVerifyVendorStateBeforeRetry: true,
      automaticVendorRetryAllowed: false,
      ...(value.automaticVendorRetryAllowed === true ? { automaticVendorRetryAllowedRedacted: true } : {}),
      retrySafetyMetadataTruth: "host_reported_retry_safety_context",
    };
  }

  return {
    manualRetryStage: "source_resolution",
    manualRetryReasonCode: "source_resolution_retryable_failure",
    manualRetryVerificationScope: "source_ref_revalidation_before_vendor_send",
    manualRetryNextOperatorAction: "Revalidate approved source refs and re-run the external media transfer before any vendor send; no vendor-state check is required for this source-resolution failure.",
    manualRetryRequiresVendorStateCheck: false,
    sourceResolveCompletedBeforeRetry: false,
    vendorSendAttemptedBeforeRetry: false,
    operatorMustVerifyVendorStateBeforeRetry: false,
    automaticVendorRetryAllowed: false,
    ...(value.automaticVendorRetryAllowed === true ? { automaticVendorRetryAllowedRedacted: true } : {}),
    retrySafetyMetadataTruth: "host_reported_retry_safety_context",
  };
}

function sanitizeSourceFileRetryOutcomes(
  value: unknown,
  actionFiles: ExternalChannelMediaFileRef[],
  aggregateMaxAttemptCount: number,
): ExternalChannelMediaTransferForegroundRetryFileOutcome[] {
  const fileCount = Math.min(actionFiles.length, MAX_HOST_FILE_REFS);
  if (!Array.isArray(value) || fileCount <= 0) return [];
  const outcomes: ExternalChannelMediaTransferForegroundRetryFileOutcome[] = [];
  const maxOutcomes = Math.min(fileCount, MAX_HOST_FILE_REFS);
  for (const item of value) {
    if (outcomes.length >= maxOutcomes) break;
    if (!isRecord(item)) continue;
    if (!Number.isSafeInteger(item.fileIndex)) continue;
    const fileIndex = Math.max(0, Math.min(fileCount - 1, Number(item.fileIndex)));
    const sourceRefFingerprint = typeof item.sourceRefFingerprint === "string"
      ? item.sourceRefFingerprint.trim().toLowerCase()
      : "";
    if (!SOURCE_REF_FINGERPRINT_PATTERN.test(sourceRefFingerprint)) continue;
    if (actionFiles[fileIndex]?.sourceRefFingerprint !== sourceRefFingerprint) continue;
    if (item.retryStatus !== "recovered" && item.retryStatus !== "exhausted") continue;

    const maxAttemptCount = clampInteger(item.maxAttemptCount, 1, aggregateMaxAttemptCount);
    const outcome: ExternalChannelMediaTransferForegroundRetryFileOutcome = {
      fileIndex,
      sourceRefFingerprint,
      retryStatus: item.retryStatus,
      retryAttemptCount: clampInteger(item.retryAttemptCount, 0, Math.max(0, maxAttemptCount - 1)),
      maxAttemptCount,
    };
    if (item.lastFailureKind === "rejected" || item.lastFailureKind === "timeout") {
      outcome.lastFailureKind = item.lastFailureKind;
    }
    const retryAfterSeconds = boundedRetryAfterSeconds(item.lastRetryAfterSeconds);
    if (retryAfterSeconds !== undefined) {
      outcome.lastRetryAfterSeconds = retryAfterSeconds;
    }
    outcomes.push(outcome);
  }
  return outcomes;
}

function withManualMediaTransferRetryOutput(output: string): string {
  return [
    output,
    "Retry UX: manual operator reinvoke only.",
    "No automatic retry was attempted. No background retry worker, retry schedule, credential persistence, approval-signature persistence, or default live delivery was created.",
  ].join("\n");
}

function clampInteger(value: unknown, min: number, max: number): number {
  if (!Number.isSafeInteger(value)) return min;
  return Math.max(min, Math.min(max, Number(value)));
}

function boundedRetryAfterSeconds(value: unknown): number | undefined {
  if (!Number.isFinite(value) || !Number.isSafeInteger(value)) return undefined;
  return Math.max(0, Math.min(MAX_RETRY_AFTER_SECONDS, Number(value)));
}

function stableJson(value: unknown): string {
  if (Array.isArray(value)) {
    return `[${value.map((item) => stableJson(item)).join(",")}]`;
  }
  if (isRecord(value)) {
    return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${stableJson(value[key])}`).join(",")}}`;
  }
  return JSON.stringify(value);
}

function optionalSafeIdentifier(value: string | undefined): { value?: string; reason?: string } | undefined {
  if (value === undefined) return undefined;
  const normalized = normalizeSafeIdentifier(value);
  return normalized ? { value: normalized } : { reason: "External media transfer identifier metadata is missing or unsafe." };
}

function normalizeSafeIdentifier(value: string | undefined): string | undefined {
  const normalized = typeof value === "string" ? value.trim() : "";
  if (!normalized || normalized.length > 160) return undefined;
  if (containsUnsafeIdentifierText(normalized)) return undefined;
  return /^[A-Za-z0-9_.:@-]+$/.test(normalized) ? normalized : undefined;
}

function containsUnsafeIdentifierText(value: string): boolean {
  const lower = value.toLowerCase();
  return lower.includes("..") ||
    lower.includes("\\") ||
    lower.includes("/") ||
    lower.includes("://") ||
    SECRET_VALUE_TEST_PATTERN.test(value) ||
    PRIVATE_URL_TEST_PATTERN.test(value);
}

function isSafeSourceRef(value: string): boolean {
  if (containsUnsafeIdentifierText(value)) return false;
  return /^(artifact|tool-result|host-media):[A-Za-z0-9_.-]{1,120}$/.test(value);
}

function isForbiddenMediaKey(key: string): boolean {
  return FORBIDDEN_MEDIA_KEY_NORMALIZED.has(normalizeMediaKey(key));
}

function normalizeMediaKey(key: string): string {
  return key.replace(/[^A-Za-z0-9]/g, "").toLowerCase();
}

function isTargetKind(value: unknown): value is "direct" | "group" | "channel" {
  return value === "direct" || value === "group" || value === "channel";
}

function isManualRetryStage(value: unknown): value is ExternalChannelMediaTransferManualRetryStage {
  return value === "source_resolution" || value === "vendor_send" || value === "host_handler";
}

function isSupportedChannel(value: string): boolean {
  return SUPPORTED_CHANNELS.includes(value as typeof SUPPORTED_CHANNELS[number]);
}

function sanitizeText(value: string): string {
  return value
    .replace(ANY_URL_PATTERN, "[REDACTED_URL]")
    .replace(PRIVATE_URL_PATTERN, "[REDACTED_URL]")
    .replace(PATH_LIKE_PATTERN, "[REDACTED_PATH]")
    .replace(REQUEST_ONLY_TARGET_ASSIGNMENT_PATTERN, "[REDACTED_REQUEST_TARGET_CONTEXT]")
    .replace(RETRY_WORK_ITEM_OBJECT_PATTERN, "[REDACTED_RETRY_WORK_ITEM_CLAIM]")
    .replace(RETRY_WORK_ITEM_CLAIM_PATTERN, "[REDACTED_RETRY_WORK_ITEM_CLAIM]")
    .replace(RETRY_WORKER_URI_PATTERN, "[REDACTED_RETRY_WORKER_REFERENCE]")
    .replace(SAFE_SOURCE_REF_PATTERN, "[REDACTED_SOURCE_REF]")
    .replace(SENSITIVE_QUERY_PARAM_PATTERN, "$1[REDACTED]")
    .replace(MEDIA_TRANSFER_SIGNATURE_PATTERN, "channel-media-transfer:[REDACTED]")
    .replace(REQUEST_ONLY_VENDOR_SEND_CONTEXT_PATTERN, "[REDACTED_REQUEST_CONTEXT]")
    .replace(SECRET_VALUE_PATTERN, "[REDACTED]");
}

function sanitizeVendorMessageId(value: string): Record<string, unknown> {
  const trimmed = value.trim();
  if (!trimmed) return {};
  const sanitized = truncateText(sanitizeText(trimmed), MAX_MEDIA_FIELD_LENGTH);
  const safe =
    sanitized === trimmed &&
    /^[A-Za-z0-9_.:@-]{1,160}$/.test(trimmed) &&
    !/\b(?:artifact|tool-result|host-media):/i.test(trimmed) &&
    !/(?:byte|bytes|base64|content)/i.test(trimmed) &&
    !/(?:^|[_.:@-])(?:token|secret|credential|signature|password|apikey|api-key|auth|bearer)(?:$|[_.:@-])/i.test(trimmed) &&
    !containsUnsafeIdentifierText(trimmed);
  if (!safe) {
    return {
      vendorMessageId: "[REDACTED_VENDOR_MESSAGE_ID]",
      vendorMessageIdRedacted: true,
    };
  }
  return { vendorMessageId: trimmed };
}

function sanitizeHostReceipt(value: unknown, maxFileCount: number): Record<string, unknown> {
  if (!isRecord(value)) return {};
  const out: Record<string, unknown> = {
    hostReceiptSource: "host_reported",
    hostReceiptVerifiedByColony: false,
    hostReceiptFilesInspectedByColony: false,
  };
  if (typeof value.receiptId === "string") {
    Object.assign(out, sanitizeReceiptId(value.receiptId));
  }
  if (typeof value.status === "string") {
    Object.assign(out, sanitizeReceiptStatus(value.status));
  }
  const deliveredCount = boundedReceiptCount(value.deliveredCount, maxFileCount);
  if (deliveredCount !== undefined) {
    out.hostReceiptDeliveredCount = deliveredCount;
  }
  const inspectedFileCount = boundedReceiptCount(value.inspectedFileCount, maxFileCount);
  if (inspectedFileCount !== undefined) {
    out.hostReceiptInspectedFileCount = inspectedFileCount;
  }
  if (typeof value.receiptUrl === "string" && value.receiptUrl.trim()) {
    out.hostReceiptUrlRedacted = true;
    out.hostReceiptUrlPersisted = false;
  }
  return out;
}

function sanitizeReceiptId(value: string): Record<string, unknown> {
  const trimmed = value.trim();
  if (!trimmed) return {};
  const sanitized = truncateText(sanitizeText(trimmed), MAX_MEDIA_FIELD_LENGTH);
  const safe =
    sanitized === trimmed &&
    /^[A-Za-z0-9_.:@-]{1,160}$/.test(trimmed) &&
    !/(?:^|[_.:@-])(?:token|secret|credential|signature|password|apikey|api-key|auth|bearer)(?:$|[_.:@-])/i.test(trimmed) &&
    !containsUnsafeIdentifierText(trimmed);
  if (!safe) {
    return {
      hostReceiptId: "[REDACTED_RECEIPT_ID]",
      hostReceiptIdRedacted: true,
    };
  }
  return { hostReceiptId: trimmed };
}

function sanitizeReceiptStatus(value: string): Record<string, unknown> {
  const normalized = value.trim().toLowerCase();
  if (SAFE_HOST_RECEIPT_STATUSES.has(normalized)) {
    return { hostReceiptStatus: normalized };
  }
  return {
    hostReceiptStatus: "[REDACTED_RECEIPT_STATUS]",
    hostReceiptStatusRedacted: true,
  };
}

function boundedReceiptCount(value: unknown, maxFileCount: number): number | undefined {
  if (!Number.isSafeInteger(value) || Number(value) < 0) return undefined;
  return Math.min(Number(value), Math.max(0, maxFileCount));
}

function truncateText(value: string, maxLength: number): string {
  const suffix = "...[TRUNCATED]";
  return value.length <= maxLength ? value : `${value.slice(0, Math.max(0, maxLength - suffix.length))}${suffix}`;
}

async function sha256Hex(value: string): Promise<string> {
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(value));
  return Array.from(new Uint8Array(digest)).map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

function displayNameForChannel(channelId: string): string {
  const normalized = normalizeChannelId(channelId);
  if (normalized === "discord") return "Discord";
  if (normalized === "slack") return "Slack";
  if (normalized === "telegram") return "Telegram";
  return normalized || "Unknown";
}

function normalizeChannelId(value: string): string {
  return String(value).trim().toLowerCase();
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}

function recordKeysAllowed(value: Record<string, unknown>, allowed: Set<string>): boolean {
  return Object.keys(value).every((key) => allowed.has(key));
}
